import React, { useState } from 'react';
import StatCard from '../components/StatCard';

const BookingsManagement = () => {
  const [filterStatus, setFilterStatus] = useState('all');

  const orders = [
    { id: 'ORD-2045', dealer: 'Metro Motors, Delhi', bike: 'Pulsar NS 200', qty: 25, amount: '₹35,50,000', status: 'confirmed', date: '2026-02-24' },
    { id: 'ORD-2044', dealer: 'Royal Rides, Mumbai', bike: 'Classic 350', qty: 15, amount: '₹29,70,000', status: 'shipped', date: '2026-02-23' },
    { id: 'ORD-2043', dealer: 'Speed Hub, Bangalore', bike: 'Yamaha MT 15', qty: 20, amount: '₹33,60,000', status: 'pending', date: '2026-02-23' },
    { id: 'ORD-2042', dealer: 'KTM Zone, Pune', bike: 'KTM Duke 200', qty: 10, amount: '₹19,20,000', status: 'delivered', date: '2026-02-22' },
    { id: 'ORD-2041', dealer: 'Bike World, Hyderabad', bike: 'KTM RC 390', qty: 5, amount: '₹19,25,000', status: 'confirmed', date: '2026-02-21' },
    { id: 'ORD-2040', dealer: 'Honda Hub, Chennai', bike: 'Honda CB350', qty: 30, amount: '₹61,50,000', status: 'pending', date: '2026-02-20' },
    { id: 'ORD-2039', dealer: 'Ride Nation, Jaipur', bike: 'Interceptor 650', qty: 8, amount: '₹24,40,000', status: 'shipped', date: '2026-02-19' },
  ];

  const statuses = ['all', 'pending', 'confirmed', 'shipped', 'delivered'];

  const getStatusBadge = (status) => {
    const map = {
      pending: 'warning', confirmed: 'info', shipped: 'primary', delivered: 'success', cancelled: 'danger'
    };
    return map[status] || 'neutral';
  };

  const filteredOrders = filterStatus === 'all'
    ? orders
    : orders.filter(o => o.status === filterStatus);

  return (
    <div>
      <div className="page-header">
        <div className="page-header-row">
          <div>
            <h1>📋 Order Management</h1>
            <p>Track and manage all bulk orders across your dealer network</p>
          </div>
          <button className="btn btn-primary">➕ Create Order</button>
        </div>
      </div>

      <div className="stats-grid">
        <StatCard icon="📦" label="Total Orders" value="156" trend="up" trendValue="12%" color="blue" />
        <StatCard icon="⏳" label="Pending Approval" value="8" trend="down" trendValue="2" color="orange" />
        <StatCard icon="🚚" label="In Transit" value="12" trend="up" trendValue="5" color="purple" />
        <StatCard icon="✅" label="Delivered" value="136" trend="up" trendValue="18%" color="green" />
      </div>

      {/* Filters */}
      <div className="filter-bar">
        {statuses.map(s => (
          <button
            key={s}
            className={`filter-chip ${filterStatus === s ? 'active' : ''}`}
            onClick={() => setFilterStatus(s)}
          >
            {s.charAt(0).toUpperCase() + s.slice(1)}
          </button>
        ))}
      </div>

      {/* Orders Table */}
      <div className="card">
        <div className="data-table-container">
          <table className="data-table">
            <thead>
              <tr>
                <th>Order ID</th>
                <th>Dealer</th>
                <th>Bike Model</th>
                <th>Quantity</th>
                <th>Amount</th>
                <th>Status</th>
                <th>Date</th>
              </tr>
            </thead>
            <tbody>
              {filteredOrders.map(order => (
                <tr key={order.id}>
                  <td className="table-cell-main">{order.id}</td>
                  <td>{order.dealer}</td>
                  <td>{order.bike}</td>
                  <td className="table-cell-main">{order.qty} units</td>
                  <td className="table-cell-main">{order.amount}</td>
                  <td>
                    <span className={`badge badge--${getStatusBadge(order.status)}`}>
                      <span className="badge-dot"></span>
                      {order.status}
                    </span>
                  </td>
                  <td style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>{order.date}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default BookingsManagement;
